#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int v;
    struct Node* next;
} Node;

int *A, *B, *headIdx, *to, *nextEdge;
int edgeCnt;
int N;
long long ans;

void addEdge(int u, int v) {
    to[edgeCnt] = v;
    nextEdge[edgeCnt] = headIdx[u];
    headIdx[u] = edgeCnt++;
    to[edgeCnt] = u;
    nextEdge[edgeCnt] = headIdx[v];
    headIdx[v] = edgeCnt++;
}

void dfs(int u, int parent, int inherited) {
    int cur = (inherited == -1) ? A[u] : inherited;
    int newInherited = inherited;
    if (cur != B[u]) {
        ans++;
        newInherited = B[u];
    }
    for (int e = headIdx[u]; e != -1; e = nextEdge[e]) {
        int v = to[e];
        if (v == parent) continue;
        dfs(v, u, newInherited);
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        A = (int*)malloc((N+1)*sizeof(int));
        B = (int*)malloc((N+1)*sizeof(int));
        for (int i = 1; i <= N; ++i) scanf("%d", &A[i]);
        for (int i = 1; i <= N; ++i) scanf("%d", &B[i]);
        headIdx = (int*)malloc((N+1)*sizeof(int));
        for (int i = 1; i <= N; ++i) headIdx[i] = -1;
        to = (int*)malloc((2*(N-1)+5)*sizeof(int));
        nextEdge = (int*)malloc((2*(N-1)+5)*sizeof(int));
        edgeCnt = 0;
        for (int i = 0; i < N-1; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            addEdge(u, v);
        }
        ans = 0;
        dfs(1, 0, -1);
        printf("%lld\n", ans);
        free(A); free(B); free(headIdx); free(to); free(nextEdge);
    }
    return 0;
}

