import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
    static List<Integer>[] adj;
    static int[] A, B;
    static long ans;
    static void dfs(int u, int parent, int inherited) {
        int cur = (inherited == -1) ? A[u] : inherited;
        int newInherited = inherited;
        if (cur != B[u]) { ans++; newInherited = B[u]; }
        for (int v : adj[u]) if (v != parent) dfs(v, u, newInherited);
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder sb = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            A = new int[N+1];
            B = new int[N+1];
            for (int i=1;i<=N;i++) A[i] = fs.nextInt();
            for (int i=1;i<=N;i++) B[i] = fs.nextInt();
            adj = new ArrayList[N+1];
            for (int i=1;i<=N;i++) adj[i] = new ArrayList<>();
            for (int i=0;i<N-1;i++) {
                int u = fs.nextInt();
                int v = fs.nextInt();
                adj[u].add(v);
                adj[v].add(u);
            }
            ans = 0;
            dfs(1, 0, -1);
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

