const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const A = new Array(N + 1);
  const B = new Array(N + 1);
  for (let i = 1; i <= N; i++) A[i] = input[idx++];
  for (let i = 1; i <= N; i++) B[i] = input[idx++];
  const adj = Array.from({ length: N + 1 }, () => []);
  for (let i = 0; i < N - 1; i++) {
    const u = input[idx++];
    const v = input[idx++];
    adj[u].push(v);
    adj[v].push(u);
  }
  let ans = 0;
  function dfs(u, parent, inherited) {
    const cur = inherited === -1 ? A[u] : inherited;
    let newInherited = inherited;
    if (cur !== B[u]) {
      ans++;
      newInherited = B[u];
    }
    for (const v of adj[u]) {
      if (v !== parent) dfs(v, u, newInherited);
    }
  }
  dfs(1, 0, -1);
  outputs.push(String(ans));
}
